const amqp = require('amqplib');
const db = require('./database');

async function processMessage(message) {
  const messageContent = JSON.parse(message.content);
  switch (messageContent.type) {
    case 'insert':
      await db.query(`INSERT INTO ${messageContent.table} (${messageContent.fields}) VALUES (${messageContent.values})`);
      break;
    case 'update':
      await db.query(`UPDATE ${messageContent.table} SET ${messageContent.fields} WHERE id = ${messageContent.id}`);
      break;
    case 'delete':
      await db.query(`DELETE FROM ${messageContent.table} WHERE id = ${messageContent.id}`);
      break;
  }
}

async function consumeMessages() {
  const connection = await amqp.connect('amqp://localhost');
  const channel = await connection.createChannel();
  const queue = 'my_queue';
  await channel.assertQueue(queue);
  channel.consume(queue, processMessage, { noAck: true });
}

consumeMessages();